svg.script:
(function () {
  const countries = document.querySelectorAll(".map-country-svg");
  countries.forEach((country) => {
    country.addEventListener("click", function () {
      countries.forEach((item) => item.classList.remove("selected-country-svg"));
      this.classList.add("selected-country-svg");

      const detail = {
        country: this.dataset.country || "Bilinmiyor",
        capital: this.dataset.capital || "—",
        id: this.id
      };

      window.dispatchEvent(new CustomEvent("imperaCountrySelected", { detail }));
    });
  });
})();
